307→export function handleUpdateObject(conn: WorldConn, r: PacketReader): void {
308→  const entries = parseUpdateObject(r);
309→  for (const entry of entries) {
310→    switch (entry.type) {
311→      case "create": {
312→        const { _changed: _co, ...objFields } = extractObjectFields(
313→          entry.fields,
314→        );
315→        let extraFields: Record<string, unknown> = {};
316→        if (
317→          entry.objectType === ObjectType.UNIT ||
318→          entry.objectType === ObjectType.PLAYER
319→        ) {
320→          const { _changed: _cu, ...rest } = extractUnitFields(entry.fields);
321→          extraFields = rest;
322→        } else if (entry.objectType === ObjectType.GAMEOBJECT) {
323→          const { _changed: _cg, ...rest } = extractGameObjectFields(
324→            entry.fields,
325→          );
326→          extraFields = rest;
327→        }
328→        const cachedName = lookupCachedName(
329→          conn,
330→          entry.guid,
331→          entry.objectType,
332→          objFields.entry,
333→        );
334→        conn.entityStore.create(entry.guid, entry.objectType, {
335→          ...objFields,
336→          ...extraFields,
337→          ...(cachedName ? { name: cachedName } : {}),
338→          ...(entry.position ? { position: entry.position } : {}),
339→          rawFields: new Map(entry.fields),
340→        } as any);
341→        if (!cachedName) {
342→          queryEntityName(conn, entry.guid, entry.objectType, objFields.entry);
343→        }
344→        break;
345→      }
346→      case "values": {
347→        const entity = conn.entityStore.get(entry.guid);
348→        if (!entity) break;
349→        const objFields = extractObjectFields(entry.fields, entity.rawFields);
350→        let extraFields: Record<string, unknown> = {};
351→        if (
352→          entity.objectType === ObjectType.UNIT ||
353→          entity.objectType === ObjectType.PLAYER
354→        ) {
355→          extraFields = extractUnitFields(entry.fields, entity.rawFields);
356→        } else if (entity.objectType === ObjectType.GAMEOBJECT) {
357→          extraFields = extractGameObjectFields(entry.fields);
358→        }
359→        const allChanged = [
360→          ...(objFields._changed || []),
361→          ...((extraFields as any)._changed || []),
362→        ];
363→        const merged: Record<string, unknown> = {};
364→        for (const key of allChanged) {
365→          if (key in extraFields) merged[key] = (extraFields as any)[key];
366→          else if (key in objFields) merged[key] = (objFields as any)[key];
367→        }
368→        conn.entityStore.update(entry.guid, merged);
369→        for (const [k, v] of entry.fields) {
370→          const existing = conn.entityStore.get(entry.guid);
371→          if (existing) existing.rawFields.set(k, v);
372→        }
373→        break;
374→      }
375→      case "movement": {
376→        conn.entityStore.setPosition(entry.guid, entry.position);
377→        break;
378→      }
379→      case "outOfRange": {
380→        for (const guid of entry.guids) conn.entityStore.destroy(guid);
381→        break;
382→      }
383→      case "nearObjects": {
384→        break;
385→      }
386→    }
387→  }
388→}
