390→export function handleCompressedUpdateObject(
391→  conn: WorldConn,
392→  r: PacketReader,
393→): void {
394→  const uncompressedSize = r.uint32LE();
395→  const compressed = r.bytes(r.remaining);
396→  const decompressed = inflateSync(compressed);
397→  if (decompressed.length !== uncompressedSize) {
398→    throw new Error(
399→      `Compressed update size mismatch: expected ${uncompressedSize}, got ${decompressed.length}`,
400→    );
401→  }
402→  handleUpdateObject(conn, new PacketReader(new Uint8Array(decompressed)));
403→}
