418→    const guidLow = Number(guid & 0xffffffffn);
419→    return conn.nameCache.get(guidLow);
420→  }
421→  if (entry === undefined) return undefined;
422→  if (objectType === ObjectType.UNIT) return conn.creatureNameCache.get(entry);
423→  if (objectType === ObjectType.GAMEOBJECT)
424→    return conn.gameObjectNameCache.get(entry);
425→  return undefined;
426→}
