177→export type WorldConn = {
178→  socket: Socket;
179→  dispatch: OpcodeDispatch;
180→  buf: AccumulatorBuffer;
181→  arc4?: Arc4;
182→  startTime: number;
183→  pendingHeader?: { size: number; opcode: number };
184→  nameCache: Map<number, string>;
185→  pendingMessages: Map<number, RawChatMessage[]>;
186→  channels: string[];
187→  lastChatMode: ChatMode;
188→  onMessage?: (msg: ChatMessage) => void;
189→  selfName: string;
190→  selfGuidLow: number;
191→  selfGuidHigh: number;
192→  partyMembers: Map<string, { guidLow: number; guidHigh: number }>;
193→  onGroupEvent?: (event: GroupEvent) => void;
194→  entityStore: EntityStore;
195→  creatureNameCache: Map<number, string>;
196→  gameObjectNameCache: Map<number, string>;
197→  onEntityEvent?: (event: EntityEvent) => void;
198→  onPacketError?: (opcode: number, err: Error) => void;
199→  pendingNameQueries: Set<string>;
200→  friendStore: FriendStore;
201→  onFriendEvent?: (event: FriendEvent) => void;
202→};
203→
204→function drainWorldPackets(conn: WorldConn): void {
205→  while (true) {
206→    if (!conn.pendingHeader) {
207→      if (conn.buf.length < INCOMING_HEADER_SIZE) break;
208→      conn.pendingHeader = decryptIncomingHeader(
209→        conn.buf.drain(INCOMING_HEADER_SIZE),
210→        conn.arc4,
211→      );
212→    }
213→    const bodySize = conn.pendingHeader.size - 2;
214→    if (conn.buf.length < bodySize) break;
215→
216→    const { opcode } = conn.pendingHeader;
217→    conn.pendingHeader = undefined;
218→    try {
219→      conn.dispatch.handle(opcode, new PacketReader(conn.buf.drain(bodySize)));
220→    } catch (err) {
221→      if (err instanceof Error) {
222→        conn.onPacketError?.(opcode, err);
223→      }
224→    }
225→  }
226→}
227→
228→async function authenticateWorld(
229→  conn: WorldConn,
230→  config: ClientConfig,
231→  auth: AuthResult,
232→): Promise<void> {
233→  const challenge = await conn.dispatch.expect(GameOpcode.SMSG_AUTH_CHALLENGE);
234→  challenge.uint32LE();
235→  const serverSeed = challenge.bytes(4);
236→
237→  const body = await buildWorldAuthPacket(
238→    config.account,
239→    auth.sessionKey,
240→    serverSeed,
241→    auth.realmId,
242→    config.clientSeed,
243→  );
244→  conn.socket.write(buildOutgoingPacket(GameOpcode.CMSG_AUTH_SESSION, body));
245→  conn.arc4 = new Arc4(auth.sessionKey);
246→
247→  const resp = await conn.dispatch.expect(GameOpcode.SMSG_AUTH_RESPONSE);
248→  const status = resp.uint8();
249→  if (status !== 0x0c) {
250→    const names: Record<number, string> = {
251→      0x0d: "system error",
252→      0x15: "account in use",
253→    };
254→    const label = names[status] ?? `status 0x${status.toString(16)}`;
255→    throw new Error(`World auth failed: ${label}`);
256→  }
257→}
258→
259→async function selectCharacter(
260→  conn: WorldConn,
261→  config: ClientConfig,
262→): Promise<void> {
263→  sendPacket(conn, GameOpcode.CMSG_CHAR_ENUM);
264→
265→  const enumReader = await conn.dispatch.expect(GameOpcode.SMSG_CHAR_ENUM);
266→  const chars = parseCharacterList(enumReader);
267→  const char = chars.find(
268→    (c) => c.name.toLowerCase() === config.character.toLowerCase(),
269→  );
270→  if (!char) {
271→    throw new Error(
272→      `Character "${config.character}" not found. Available: ${chars.map((c) => c.name).join(", ")}`,
273→    );
274→  }
275→
276→  conn.selfName = char.name;
277→  conn.selfGuidLow = char.guidLow;
278→  conn.selfGuidHigh = char.guidHigh;
279→
280→  const w = new PacketWriter();
281→  w.uint32LE(char.guidLow);
282→  w.uint32LE(char.guidHigh);
283→  sendPacket(conn, GameOpcode.CMSG_PLAYER_LOGIN, w.finish());
284→
285→  await conn.dispatch.expect(GameOpcode.SMSG_LOGIN_VERIFY_WORLD);
286→}
287→
288→function startPingLoop(
289→  conn: WorldConn,
290→  intervalMs: number,
291→): ReturnType<typeof setInterval> {
292→  return setInterval(() => {
293→    const w = new PacketWriter();
294→    w.uint32LE(0);
295→    w.uint32LE(0);
296→    sendPacket(conn, GameOpcode.CMSG_PING, w.finish());
297→  }, intervalMs);
298→}
