462→          conn.lastChatMode = { type: "yell" };
463→          sendPacket(
464→            conn,
465→            GameOpcode.CMSG_MESSAGE_CHAT,
466→            buildChatMessage(ChatType.YELL, lang, message),
467→          );
468→        },
469→        sendGuild(message) {
470→          conn.lastChatMode = { type: "guild" };
471→          sendPacket(
472→            conn,
473→            GameOpcode.CMSG_MESSAGE_CHAT,
474→            buildChatMessage(ChatType.GUILD, lang, message),
475→          );
476→        },
477→        sendParty(message) {
478→          conn.lastChatMode = { type: "party" };
479→          sendPacket(
480→            conn,
481→            GameOpcode.CMSG_MESSAGE_CHAT,
482→            buildChatMessage(ChatType.PARTY, lang, message),
483→          );
484→        },
485→        sendRaid(message) {
486→          conn.lastChatMode = { type: "raid" };
487→          sendPacket(
488→            conn,
489→            GameOpcode.CMSG_MESSAGE_CHAT,
490→            buildChatMessage(ChatType.RAID, lang, message),
491→          );
492→        },
493→        sendEmote(message) {
494→          conn.lastChatMode = { type: "emote" };
495→          sendPacket(
496→            conn,
497→            GameOpcode.CMSG_MESSAGE_CHAT,
498→            buildChatMessage(ChatType.EMOTE, lang, message),
499→          );
500→        },
501→        sendDnd(message) {
502→          sendPacket(
503→            conn,
504→            GameOpcode.CMSG_MESSAGE_CHAT,
505→            buildChatMessage(ChatType.DND, lang, message),
506→          );
507→        },
508→        sendAfk(message) {
509→          sendPacket(
510→            conn,
511→            GameOpcode.CMSG_MESSAGE_CHAT,
512→            buildChatMessage(ChatType.AFK, lang, message),
513→          );
514→        },
515→        sendChannel(channel, message) {
516→          conn.lastChatMode = { type: "channel", channel };
517→          sendPacket(
518→            conn,
519→            GameOpcode.CMSG_MESSAGE_CHAT,
520→            buildChatMessage(ChatType.CHANNEL, lang, message, channel),
521→          );
522→        },
523→        getChannel(index) {
524→          return conn.channels[index - 1];
525→        },
526→        async who(opts = {}) {
527→          sendPacket(conn, GameOpcode.CMSG_WHO, buildWhoRequest(opts));
528→          const r = await conn.dispatch.expect(GameOpcode.SMSG_WHO);
529→          return parseWhoResponse(r);
530→        },
531→        getLastChatMode() {
532→          return conn.lastChatMode;
533→        },
534→        setLastChatMode(mode) {
535→          conn.lastChatMode = mode;
536→        },
537→        sendInCurrentMode(message) {
538→          const mode = conn.lastChatMode;
539→          switch (mode.type) {
540→            case "say":
541→              handle.sendSay(message);
542→              break;
543→            case "yell":
544→              handle.sendYell(message);
545→              break;
546→            case "guild":
547→              handle.sendGuild(message);
548→              break;
549→            case "party":
550→              handle.sendParty(message);
551→              break;
552→            case "raid":
553→              handle.sendRaid(message);
554→              break;
555→            case "emote":
556→              handle.sendEmote(message);
557→              break;
558→            case "whisper":
559→              handle.sendWhisper(mode.target, message);
560→              break;
561→            case "channel":
562→              handle.sendChannel(mode.channel, message);
563→              break;
564→          }
565→        },
566→        invite(name) {
567→          sendPacket(
568→            conn,
569→            GameOpcode.CMSG_GROUP_INVITE,
570→            buildGroupInvite(name),
571→          );
572→        },
573→        uninvite(name) {
574→          sendPacket(
575→            conn,
576→            GameOpcode.CMSG_GROUP_UNINVITE,
577→            buildGroupUninvite(name),
578→          );
579→        },
580→        leaveGroup() {
581→          sendPacket(conn, GameOpcode.CMSG_GROUP_DISBAND, buildGroupDisband());
582→        },
583→        setLeader(name) {
584→          const member = conn.partyMembers.get(name);
585→          if (!member) {
586→            conn.onMessage?.({
587→              type: ChatType.SYSTEM,
588→              sender: "",
589→              message: `"${name}" is not in your party.`,
590→            });
591→            return;
592→          }
593→          sendPacket(
594→            conn,
595→            GameOpcode.CMSG_GROUP_SET_LEADER,
596→            buildGroupSetLeader(member.guidLow, member.guidHigh),
597→          );
598→        },
599→        acceptInvite() {
600→          sendPacket(conn, GameOpcode.CMSG_GROUP_ACCEPT, buildGroupAccept());
601→        },
602→        declineInvite() {
603→          sendPacket(conn, GameOpcode.CMSG_GROUP_DECLINE, buildGroupDecline());
604→        },
605→        onGroupEvent(cb) {
606→          conn.onGroupEvent = cb;
607→        },
608→        onEntityEvent(cb) {
609→          conn.onEntityEvent = cb;
610→        },
611→        onPacketError(cb) {
612→          conn.onPacketError = cb;
613→        },
614→        getNearbyEntities() {
615→          return conn.entityStore.all();
616→        },
617→        getFriends() {
618→          return conn.friendStore.all();
619→        },
620→        addFriend(name) {
621→          sendPacket(
622→            conn,
623→            GameOpcode.CMSG_ADD_FRIEND,
624→            buildAddFriend(name, ""),
625→          );
626→        },
627→        removeFriend(name) {
628→          const friend = conn.friendStore.findByName(name);
629→          if (!friend) {
630→            conn.onMessage?.({
631→              type: ChatType.SYSTEM,
632→              sender: "",
633→              message: `"${name}" is not on your friends list.`,
634→            });
635→            return;
636→          }
637→          sendPacket(
638→            conn,
639→            GameOpcode.CMSG_DEL_FRIEND,
640→            buildDelFriend(friend.guid),
641→          );
642→        },
643→        sendRoll(min, max) {
644→          sendPacket(
645→            conn,
646→            GameOpcode.MSG_RANDOM_ROLL,
647→            buildRandomRoll(min, max),
648→          );
649→        },
650→        onFriendEvent(cb) {
651→          conn.onFriendEvent = cb;
652→        },
653→      };
654→      resolve(handle);
655→    }
656→
657→    login().catch((err) => {
658→      done = true;
659→      clearInterval(pingInterval);
660→      reject(err);
661→      conn.socket?.end();
662→    });
663→
664→    Bun.connect({
665→      hostname: auth.realmHost,
666→      port: auth.realmPort,
667→      socket: {
668→        open(s) {
669→          conn.socket = s;
670→        },
671→        data(_s, data) {
672→          conn.buf.append(new Uint8Array(data));
673→          drainWorldPackets(conn);
674→        },
675→        close() {
676→          clearInterval(pingInterval);
677→          conn.entityStore.clear();
678→          if (!done) reject(new Error("World connection closed"));
679→          closedResolve();
680→        },
681→      },
682→    }).catch(reject);
683→  });
684→}
