 34→  const rest = spaceIdx === -1 ? "" : input.slice(spaceIdx + 1);
 35→
 36→  switch (cmd) {
 37→    case "/s":
 38→    case "/say":
 39→      return { type: "say", message: rest };
 40→    case "/y":
 41→    case "/yell":
 42→      return { type: "yell", message: rest };
 43→    case "/g":
 44→    case "/guild":
 45→      return { type: "guild", message: rest };
 46→    case "/p":
 47→    case "/party":
 48→      return { type: "party", message: rest };
 49→    case "/raid":
 50→      return { type: "raid", message: rest };
 51→    case "/w":
 52→    case "/whisper": {
 53→      const targetEnd = rest.indexOf(" ");
 54→      if (targetEnd === -1)
 55→        return { type: "whisper", target: rest, message: "" };
 56→      return {
 57→        type: "whisper",
