135→        type: "whisper",
136→        target: rest.slice(0, targetEnd),
137→        message: rest.slice(targetEnd + 1),
138→      };
139→    }
140→    case "READ":
141→      return { type: "read" };
142→    case "READ_JSON":
143→      return { type: "read_json" };
144→    case "READ_WAIT": {
145→      const ms = parseInt(rest, 10);
146→      if (!Number.isFinite(ms) || ms < 0) return undefined;
147→      return { type: "read_wait", ms: Math.min(ms, 60_000) };
148→    }
149→    case "READ_WAIT_JSON": {
150→      const ms = parseInt(rest, 10);
