214→export function writeLines(socket: IpcSocket, lines: string[]): void {
215→  for (const line of lines) socket.write(line + "\n");
216→  socket.write("\n");
217→}
218→
219→function drainText(events: RingBuffer<EventEntry>): string[] {
220→  return events.drain().flatMap((e) => (e.text !== undefined ? [e.text] : []));
221→}
222→
223→function drainJson(events: RingBuffer<EventEntry>): string[] {
224→  return events.drain().map((e) => e.json);
225→}
226→
227→function sliceText(events: RingBuffer<EventEntry>, from: number): string[] {
228→  return events
229→    .slice(from)
230→    .flatMap((e) => (e.text !== undefined ? [e.text] : []));
231→}
232→
233→function sliceJson(events: RingBuffer<EventEntry>, from: number): string[] {
234→  return events.slice(from).map((e) => e.json);
235→}
236→
237→export async function dispatchCommand(
238→  cmd: IpcCommand,
239→  handle: WorldHandle,
240→  events: RingBuffer<EventEntry>,
241→  socket: IpcSocket,
242→  cleanup: () => void,
243→): Promise<boolean> {
244→  switch (cmd.type) {
245→    case "chat": {
246→      handle.sendInCurrentMode(cmd.message);
247→      const mode = handle.getLastChatMode();
248→      const label =
249→        mode.type === "whisper"
250→          ? `WHISPER ${mode.target}`
251→          : mode.type === "channel"
252→            ? `CHANNEL ${mode.channel}`
253→            : mode.type.toUpperCase();
254→      writeLines(socket, [`OK ${label}`]);
255→      return false;
256→    }
257→    case "say":
258→      handle.sendSay(cmd.message);
259→      writeLines(socket, ["OK"]);
260→      return false;
261→    case "yell":
262→      handle.sendYell(cmd.message);
263→      writeLines(socket, ["OK"]);
264→      return false;
265→    case "guild":
266→      handle.sendGuild(cmd.message);
267→      writeLines(socket, ["OK"]);
268→      return false;
269→    case "party":
270→      handle.sendParty(cmd.message);
271→      writeLines(socket, ["OK"]);
272→      return false;
273→    case "emote":
274→      handle.sendEmote(cmd.message);
275→      writeLines(socket, ["OK"]);
276→      return false;
277→    case "dnd":
278→      handle.sendDnd(cmd.message);
279→      writeLines(socket, ["OK"]);
280→      return false;
281→    case "afk":
282→      handle.sendAfk(cmd.message);
283→      writeLines(socket, ["OK"]);
284→      return false;
285→    case "whisper":
286→      handle.sendWhisper(cmd.target, cmd.message);
287→      writeLines(socket, ["OK"]);
288→      return false;
289→    case "roll":
290→      handle.sendRoll(cmd.min, cmd.max);
291→      writeLines(socket, ["OK"]);
292→      return false;
293→    case "read":
294→      writeLines(socket, drainText(events));
295→      return false;
296→    case "read_json":
297→      writeLines(socket, drainJson(events));
298→      return false;
299→    case "read_wait": {
300→      const start = events.writePos;
301→      await new Promise<void>((resolve) => {
302→        setTimeout(() => {
303→          writeLines(socket, sliceText(events, start));
304→          resolve();
305→        }, cmd.ms);
306→      });
307→      return false;
308→    }
309→    case "read_wait_json": {
310→      const start = events.writePos;
311→      await new Promise<void>((resolve) => {
312→        setTimeout(() => {
313→          writeLines(socket, sliceJson(events, start));
314→          resolve();
315→        }, cmd.ms);
316→      });
317→      return false;
318→    }
319→    case "stop":
320→      writeLines(socket, ["OK"]);
321→      cleanup();
322→      return true;
323→    case "status":
324→      writeLines(socket, ["CONNECTED"]);
325→      return false;
326→    case "who": {
327→      const results = await handle.who(cmd.filter ? { name: cmd.filter } : {});
328→      writeLines(socket, formatWhoResults(results).split("\n"));
329→      return false;
330→    }
331→    case "who_json": {
332→      const results = await handle.who(cmd.filter ? { name: cmd.filter } : {});
333→      writeLines(socket, [formatWhoResultsJson(results)]);
334→      return false;
335→    }
336→    case "invite":
337→      handle.invite(cmd.target);
338→      writeLines(socket, ["OK"]);
339→      return false;
340→    case "kick":
341→      handle.uninvite(cmd.target);
342→      writeLines(socket, ["OK"]);
343→      return false;
344→    case "leave":
345→      handle.leaveGroup();
346→      writeLines(socket, ["OK"]);
347→      return false;
348→    case "leader":
349→      handle.setLeader(cmd.target);
350→      writeLines(socket, ["OK"]);
351→      return false;
352→    case "accept":
353→      handle.acceptInvite();
354→      writeLines(socket, ["OK"]);
355→      return false;
356→    case "decline":
357→      handle.declineInvite();
358→      writeLines(socket, ["OK"]);
359→      return false;
360→    case "nearby": {
361→      const entities = handle.getNearbyEntities();
362→      writeLines(socket, entities.map(formatNearbyLine));
363→      return false;
364→    }
365→    case "nearby_json": {
366→      const entities = handle.getNearbyEntities();
367→      writeLines(
368→        socket,
369→        entities.map((e) => JSON.stringify(formatNearbyObj(e))),
370→      );
371→      return false;
372→    }
373→    case "friends": {
374→      const friends = handle.getFriends();
375→      writeLines(socket, formatFriendList(friends).split("\n"));
376→      return false;
377→    }
378→    case "friends_json": {
379→      const friends = handle.getFriends();
380→      writeLines(socket, [formatFriendListJson(friends)]);
381→      return false;
382→    }
383→    case "add_friend":
384→      handle.addFriend(cmd.target);
385→      writeLines(socket, ["OK"]);
386→      return false;
387→    case "del_friend":
388→      handle.removeFriend(cmd.target);
389→      writeLines(socket, ["OK"]);
390→      return false;
391→    case "unimplemented":
392→      writeLines(socket, [`UNIMPLEMENTED ${cmd.feature}`]);
393→      return false;
394→  }
395→}
396→
397→function objectTypeName(type: ObjectType): string {
398→  switch (type) {
399→    case ObjectType.UNIT:
400→      return "NPC";
401→    case ObjectType.PLAYER:
402→      return "Player";
403→    default:
404→      return `type ${type}`;
405→  }
406→}
407→
408→function formatNearbyLine(entity: Entity): string {
409→  if (
410→    entity.objectType === ObjectType.UNIT ||
411→    entity.objectType === ObjectType.PLAYER
412→  ) {
413→    const unit = entity as UnitEntity;
414→    const name = entity.name ?? "Unknown";
415→    const kind = objectTypeName(entity.objectType);
416→    const level = unit.level > 0 ? `, level ${unit.level}` : "";
417→    const hp = `HP ${unit.health}/${unit.maxHealth}`;
418→    const pos = entity.position
419→      ? ` at ${entity.position.x.toFixed(2)}, ${entity.position.y.toFixed(2)}, ${entity.position.z.toFixed(2)}`
420→      : "";
421→    return `${name} (${kind}${level}) ${hp}${pos}`;
422→  }
423→  if (entity.objectType === ObjectType.GAMEOBJECT) {
424→    const name = entity.name ?? "Unknown";
425→    const pos = entity.position
426→      ? ` at ${entity.position.x.toFixed(2)}, ${entity.position.y.toFixed(2)}, ${entity.position.z.toFixed(2)}`
427→      : "";
428→    return `${name} (GameObject)${pos}`;
429→  }
430→  return `Entity 0x${entity.guid.toString(16)} (${objectTypeName(entity.objectType)})`;
431→}
432→
433→function objectTypeString(type: ObjectType): string {
434→  switch (type) {
435→    case ObjectType.UNIT:
436→      return "unit";
437→    case ObjectType.PLAYER:
438→      return "player";
439→    case ObjectType.GAMEOBJECT:
440→      return "gameobject";
441→    default:
442→      return "object";
443→  }
444→}
445→
446→function formatNearbyObj(entity: Entity): Record<string, unknown> {
447→  const obj: Record<string, unknown> = {
448→    guid: `0x${entity.guid.toString(16)}`,
449→    type: objectTypeString(entity.objectType),
450→    name: entity.name,
451→  };
452→  if (
453→    entity.objectType === ObjectType.UNIT ||
454→    entity.objectType === ObjectType.PLAYER
455→  ) {
456→    const unit = entity as UnitEntity;
457→    obj["level"] = unit.level;
458→    obj["health"] = unit.health;
459→    obj["maxHealth"] = unit.maxHealth;
460→  }
461→  if (entity.objectType === ObjectType.GAMEOBJECT) {
462→    obj["gameObjectType"] = (entity as GameObjectEntity).gameObjectType;
463→  }
464→  if (entity.position) {
465→    obj["x"] = entity.position.x;
466→    obj["y"] = entity.position.y;
467→    obj["z"] = entity.position.z;
468→  }
469→  return obj;
470→}
471→
472→function formatGroupEventObj(event: GroupEvent): Record<string, unknown> {
473→  switch (event.type) {
474→    case "invite_received":
475→      return { type: "GROUP_INVITE", from: event.from };
476→    case "command_result":
477→      return {
