275→export function formatFriendList(friends: FriendEntry[]): string {
276→  if (friends.length === 0) return "[friends] No friends on your list";
277→  const lines = friends.map((f) => {
278→    const name = f.name || `guid:${Number(f.guid & 0xffffffffn)}`;
279→    if (f.status === FriendStatus.OFFLINE) return `  ${name} — Offline`;
