281→    const statusLabel = friendStatusLabel(f.status);
282→    return `  ${name} — ${statusLabel}, Level ${f.level} ${cls}`;
283→  });
284→  const online = friends.filter(
285→    (f) => f.status !== FriendStatus.OFFLINE,
286→  ).length;
287→  return `[friends] ${online}/${friends.length} online\n${lines.join("\n")}`;
