import { ChatType, PartyOperation, PartyResult } from "wow/protocol/opcodes";
import { ObjectType } from "wow/protocol/entity-fields";
import { FriendStatus } from "wow/protocol/social";
import { stripColorCodes } from "lib/strip-colors";
import type { ChatMessage, ChatMode, WhoResult, GroupEvent } from "wow/client";
import type { EntityEvent, UnitEntity } from "wow/entity-store";
import type { FriendEntry, FriendEvent } from "wow/friend-store";
import type { IgnoreEntry, IgnoreEvent } from "wow/ignore-store";
import type { LogEntry } from "lib/session-log";

const CHAT_TYPE_LABELS: Record<number, string> = {
  [ChatType.SYSTEM]: "system",
  [ChatType.SAY]: "say",
  [ChatType.PARTY]: "party",
  [ChatType.RAID]: "raid",
  [ChatType.GUILD]: "guild",
  [ChatType.OFFICER]: "officer",
  [ChatType.YELL]: "yell",
  [ChatType.WHISPER]: "whisper from",
  [ChatType.WHISPER_INFORM]: "whisper to",
  [ChatType.EMOTE]: "emote",
  [ChatType.CHANNEL]: "channel",
  [ChatType.RAID_LEADER]: "raid leader",
  [ChatType.RAID_WARNING]: "raid warning",
  [ChatType.PARTY_LEADER]: "party leader",
  [ChatType.ROLL]: "roll",
};

export function formatMessage(msg: ChatMessage): string {
  const message = stripColorCodes(msg.message);
  const label = CHAT_TYPE_LABELS[msg.type] ?? `type ${msg.type}`;

  if (msg.type === ChatType.WHISPER) {
    return `[whisper from ${msg.sender}] ${message}`;
  }
  if (msg.type === ChatType.WHISPER_INFORM) {
    return `[whisper to ${msg.sender}] ${message}`;
  }
  if (
    msg.type === ChatType.SYSTEM &&
    (msg.origin === "server" || msg.origin === "notification")
  ) {
    return `[server] ${message}`;
  }
  if (msg.type === ChatType.SYSTEM) {
    return `[system] ${message}`;
  }
  if (msg.type === ChatType.ROLL) {
    return `[roll] ${msg.sender} ${message}`;
  }
  if (msg.type === ChatType.CHANNEL && msg.channel) {
    return `[${msg.channel}] ${msg.sender}: ${message}`;
  }
  return `[${label}] ${msg.sender}: ${message}`;
}

const JSON_TYPE_LABELS: Record<number, string> = {
  [ChatType.SYSTEM]: "SYSTEM",
  [ChatType.SAY]: "SAY",
  [ChatType.PARTY]: "PARTY",
  [ChatType.RAID]: "RAID",
  [ChatType.GUILD]: "GUILD",
  [ChatType.OFFICER]: "OFFICER",
  [ChatType.YELL]: "YELL",
  [ChatType.WHISPER]: "WHISPER_FROM",
  [ChatType.WHISPER_INFORM]: "WHISPER_TO",
  [ChatType.EMOTE]: "EMOTE",
  [ChatType.CHANNEL]: "CHANNEL",
  [ChatType.RAID_LEADER]: "RAID_LEADER",
  [ChatType.RAID_WARNING]: "RAID_WARNING",
  [ChatType.PARTY_LEADER]: "PARTY_LEADER",
  [ChatType.ROLL]: "ROLL",
};

export function formatMessageObj(msg: ChatMessage): LogEntry {
  const type =
    msg.origin === "server"
      ? "SERVER_BROADCAST"
      : msg.origin === "notification"
        ? "NOTIFICATION"
        : (JSON_TYPE_LABELS[msg.type] ?? `TYPE_${msg.type}`);
  const obj: LogEntry = {
    type,
    sender: msg.sender,
    message: stripColorCodes(msg.message),
  };
  if (msg.channel) obj.channel = msg.channel;
  return obj;
}

export function formatMessageJson(msg: ChatMessage): string {
  return JSON.stringify(formatMessageObj(msg));
}

export function formatError(message: string): string {
  return `[system] ${message}`;
}

export function formatWhoResults(results: WhoResult[]): string {
  const names =
    results.map((r) => `${r.name} (${r.level})`).join(", ") || "none";
  return `[who] ${results.length} results: ${names}`;
}

export function formatWhoResultsJson(results: WhoResult[]): string {
  return JSON.stringify({
    type: "WHO",
    count: results.length,
    results: results.map((r) => ({
      name: r.name,
      guild: r.guild,
      level: r.level,
      classId: r.classId,
      race: r.race,
      gender: r.gender,
      zone: r.zone,
    })),
  });
}

export function formatPrompt(mode: ChatMode): string {
  switch (mode.type) {
    case "whisper":
      return `[whisper: ${mode.target}] > `;
    case "channel":
      return `[${mode.channel}] > `;
    default:
      return `[${mode.type}] > `;
  }
}

function partyResultLabel(result: number): string {
  switch (result) {
    case PartyResult.BAD_PLAYER_NAME:
      return "player not found";
    case PartyResult.GROUP_FULL:
      return "group is full";
    case PartyResult.ALREADY_IN_GROUP:
      return "already in a group";
    case PartyResult.NOT_LEADER:
      return "you are not the leader";
    case PartyResult.PLAYER_WRONG_FACTION:
      return "wrong faction";
    case PartyResult.IGNORING_YOU:
      return "player is ignoring you";
    default:
      return `error ${result}`;
  }
}

export function formatGroupEvent(event: GroupEvent): string | undefined {
  switch (event.type) {
    case "invite_received":
      return `[group] ${event.from} invites you to a group`;
    case "command_result": {
      const verb =
        event.operation === PartyOperation.UNINVITE
          ? "kick"
          : event.operation === PartyOperation.LEAVE
            ? "leave"
            : "invite";
      const label =
        event.result === PartyResult.SUCCESS
          ? verb === "kick"
            ? `Removed ${event.target} from group`
            : verb === "leave"
              ? "Left the group"
              : `Invited ${event.target}`
          : `Cannot ${verb}${event.target ? ` ${event.target}` : ""}: ${partyResultLabel(event.result)}`;
      return `[group] ${label}`;
    }
    case "leader_changed":
      return `[group] ${event.name} is now the group leader`;
    case "group_destroyed":
      return "[group] Group has been disbanded";
    case "kicked":
      return "[group] You have been removed from the group";
    case "invite_declined":
      return `[group] ${event.name} has declined your invitation`;
    case "group_list":
    case "member_stats":
      return undefined;
  }
}

export function formatEntityEvent(event: EntityEvent): string | undefined {
  switch (event.type) {
    case "appear": {
      const e = event.entity;
      if (!e.name) return undefined;
      if (
        e.objectType === ObjectType.UNIT ||
        e.objectType === ObjectType.PLAYER
      ) {
        const unit = e as UnitEntity;
        const kind = e.objectType === ObjectType.PLAYER ? "Player" : "NPC";
        const levelStr = unit.level > 0 ? `, level ${unit.level}` : "";
        return `[world] ${e.name} appeared (${kind}${levelStr})`;
      }
      if (e.objectType === ObjectType.GAMEOBJECT) {
        return `[world] ${e.name} appeared (GameObject)`;
      }
      return undefined;
    }
    case "disappear": {
      const name = event.name ?? "Unknown entity";
      return `[world] ${name} left range`;
    }
    case "update": {
      if (!event.changed.includes("name") || !event.entity.name)
        return undefined;
      return formatEntityEvent({ type: "appear", entity: event.entity });
    }
  }
}

export function formatEntityEventObj(
  event: EntityEvent,
): Record<string, unknown> | undefined {
  switch (event.type) {
    case "appear": {
      const e = event.entity;
      const obj: Record<string, unknown> = {
        type: "ENTITY_APPEAR",
        guid: `0x${e.guid.toString(16)}`,
        objectType: e.objectType,
        name: e.name,
      };
      if (
        e.objectType === ObjectType.UNIT ||
        e.objectType === ObjectType.PLAYER
      ) {
        const unit = e as UnitEntity;
        obj["level"] = unit.level;
        obj["health"] = unit.health;
        obj["maxHealth"] = unit.maxHealth;
      }
      if (e.position) {
        obj["x"] = e.position.x;
        obj["y"] = e.position.y;
        obj["z"] = e.position.z;
      }
      return obj;
    }
    case "disappear":
      return {
        type: "ENTITY_DISAPPEAR",
        guid: `0x${event.guid.toString(16)}`,
        name: event.name,
      };
    case "update":
      return undefined;
  }
}

const CLASS_NAMES: Record<number, string> = {
  1: "Warrior",
  2: "Paladin",
  3: "Hunter",
  4: "Rogue",
  5: "Priest",
  6: "Death Knight",
  7: "Shaman",
  8: "Mage",
  9: "Warlock",
  11: "Druid",
};

function friendStatusLabel(status: number): string {
  if (status === FriendStatus.AFK) return "AFK";
  if (status === FriendStatus.DND) return "DND";
  if (status !== FriendStatus.OFFLINE) return "Online";
  return "Offline";
}

export function formatFriendList(friends: FriendEntry[]): string {
  if (friends.length === 0) return "[friends] No friends on your list";
  const lines = friends.map((f) => {
    const name = f.name || `guid:${Number(f.guid & 0xffffffffn)}`;
    if (f.status === FriendStatus.OFFLINE) return `  ${name} — Offline`;
    const cls = CLASS_NAMES[f.playerClass] ?? `class ${f.playerClass}`;
    const statusLabel = friendStatusLabel(f.status);
    return `  ${name} — ${statusLabel}, Level ${f.level} ${cls}`;
  });
  const online = friends.filter(
    (f) => f.status !== FriendStatus.OFFLINE,
  ).length;
  return `[friends] ${online}/${friends.length} online\n${lines.join("\n")}`;
}

export function formatFriendListJson(friends: FriendEntry[]): string {
  return JSON.stringify({
    type: "FRIENDS",
    count: friends.length,
    online: friends.filter((f) => f.status !== FriendStatus.OFFLINE).length,
    friends: friends.map((f) => ({
      guid: `0x${f.guid.toString(16)}`,
      name: f.name,
      note: f.note,
      status: friendStatusLabel(f.status).toUpperCase(),
      level: f.level,
      class: CLASS_NAMES[f.playerClass] ?? `class ${f.playerClass}`,
      area: f.area,
    })),
  });
}

function friendResultLabel(result: number): string {
  const labels: Record<number, string> = {
    0x00: "database error",
    0x01: "friends list is full",
    0x04: "player not found",
    0x08: "already on friends list",
    0x09: "cannot add yourself",
    0x0a: "cannot add enemy faction",
  };
  return labels[result] ?? `error ${result}`;
}

export function formatFriendEvent(event: FriendEvent): string | undefined {
  switch (event.type) {
    case "friend-online": {
      const f = event.friend;
      const cls = CLASS_NAMES[f.playerClass] ?? "";
      const lvl = f.level ? `Level ${f.level}` : "";
      const detail = [lvl, cls].filter(Boolean).join(" ");
      return `[friends] ${f.name || "Unknown"} is now online${detail ? ` (${detail})` : ""}`;
    }
    case "friend-offline":
      return `[friends] ${event.name || "Unknown"} went offline`;
    case "friend-added": {
      const f = event.friend;
      return `[friends] ${f.name || "Unknown"} added to friends list`;
    }
    case "friend-removed":
      return `[friends] ${event.name || "Unknown"} removed from friends list`;
    case "friend-error":
      return `[friends] Error: ${friendResultLabel(event.result)}`;
    case "friend-list":
      return undefined;
  }
}

export function formatFriendEventObj(
  event: FriendEvent,
): Record<string, unknown> | undefined {
  switch (event.type) {
    case "friend-online":
      return {
        type: "FRIEND_ONLINE",
        name: event.friend.name,
        level: event.friend.level,
        class: CLASS_NAMES[event.friend.playerClass],
        area: event.friend.area,
      };
    case "friend-offline":
      return { type: "FRIEND_OFFLINE", name: event.name };
    case "friend-added":
      return { type: "FRIEND_ADDED", name: event.friend.name };
    case "friend-removed":
      return { type: "FRIEND_REMOVED", name: event.name };
    case "friend-error":
      return {
        type: "FRIEND_ERROR",
        result: event.result,
        message: friendResultLabel(event.result),
      };
    case "friend-list":
      return undefined;
  }
}

import { RingBuffer } from "lib/ring-buffer";
import { parseCommand } from "ui/commands";
import {
  formatMessage,
  formatMessageObj,
  formatWhoResults,
  formatWhoResultsJson,
  formatGroupEvent,
  formatEntityEvent,
  formatEntityEventObj,
  formatFriendList,
  formatFriendListJson,
  formatFriendEvent,
  formatFriendEventObj,
} from "ui/format";
import type { FriendEvent } from "wow/friend-store";
import { SessionLog, type LogEntry } from "lib/session-log";
import type { WorldHandle, ChatMessage, GroupEvent } from "wow/client";
import { ObjectType } from "wow/protocol/entity-fields";
import type {
  Entity,
  UnitEntity,
  GameObjectEntity,
  EntityEvent,
} from "wow/entity-store";

export type EventEntry = { text: string | undefined; json: string };

export type IpcSocket = {
  write(data: string | Uint8Array): number;
  end(): void;
};

export type IpcCommand =
  | { type: "chat"; message: string }
  | { type: "say"; message: string }
  | { type: "yell"; message: string }
  | { type: "guild"; message: string }
  | { type: "party"; message: string }
  | { type: "emote"; message: string }
  | { type: "dnd"; message: string }
  | { type: "afk"; message: string }
  | { type: "whisper"; target: string; message: string }
  | { type: "read" }
  | { type: "read_json" }
  | { type: "read_wait"; ms: number }
  | { type: "read_wait_json"; ms: number }
  | { type: "stop" }
  | { type: "status" }
  | { type: "who"; filter?: string }
  | { type: "who_json"; filter?: string }
  | { type: "invite"; target: string }
  | { type: "kick"; target: string }
  | { type: "leave" }
  | { type: "leader"; target: string }
  | { type: "accept" }
  | { type: "decline" }
  | { type: "nearby" }
  | { type: "nearby_json" }
  | { type: "friends" }
  | { type: "friends_json" }
  | { type: "add_friend"; target: string }
  | { type: "del_friend"; target: string }
  | { type: "roll"; min: number; max: number }
  | { type: "unimplemented"; feature: string };

export function parseIpcCommand(line: string): IpcCommand | undefined {
  if (line.startsWith("/")) {
    const parsed = parseCommand(line);
    switch (parsed.type) {
      case "say":
      case "yell":
      case "guild":
      case "party":
      case "emote":
      case "dnd":
      case "afk":
        return parsed;
      case "whisper":
        return parsed;
      case "who":
        return parsed.target
          ? { type: "who", filter: parsed.target }
          : { type: "who" };
      case "invite":
      case "kick":
      case "leave":
      case "leader":
      case "accept":
      case "decline":
        return parsed;
      case "friends":
        return { type: "friends" };
      case "add-friend":
        return { type: "add_friend", target: parsed.target };
      case "remove-friend":
        return { type: "del_friend", target: parsed.target };
      case "roll":
        return parsed;
      case "unimplemented":
        return parsed;
      default:
        return { type: "say", message: line };
    }
  }

  const spaceIdx = line.indexOf(" ");
  const verb = spaceIdx === -1 ? line : line.slice(0, spaceIdx);
  const rest = spaceIdx === -1 ? "" : line.slice(spaceIdx + 1);

  switch (verb) {
    case "SAY":
    case "YELL":
    case "GUILD":
    case "PARTY":
    case "EMOTE":
    case "DND":
    case "AFK":
      return {
        type: verb.toLowerCase() as
          | "say"
          | "yell"
          | "guild"
          | "party"
          | "emote"
          | "dnd"
          | "afk",
        message: rest,
      };
    case "WHISPER": {
      const targetEnd = rest.indexOf(" ");
      if (targetEnd === -1)
        return { type: "whisper", target: rest, message: "" };
      return {
        type: "whisper",
        target: rest.slice(0, targetEnd),
        message: rest.slice(targetEnd + 1),
      };
    }
    case "READ":
      return { type: "read" };
    case "READ_JSON":
      return { type: "read_json" };
    case "READ_WAIT": {
      const ms = parseInt(rest, 10);
      if (!Number.isFinite(ms) || ms < 0) return undefined;
      return { type: "read_wait", ms: Math.min(ms, 60_000) };
    }
    case "READ_WAIT_JSON": {
      const ms = parseInt(rest, 10);
      if (!Number.isFinite(ms) || ms < 0) return undefined;
      return { type: "read_wait_json", ms: Math.min(ms, 60_000) };
    }
    case "STOP":
      return { type: "stop" };
    case "STATUS":
      return { type: "status" };
    case "WHO":
      return rest ? { type: "who", filter: rest } : { type: "who" };
    case "WHO_JSON":
      return rest ? { type: "who_json", filter: rest } : { type: "who_json" };
    case "INVITE":
      return rest ? { type: "invite", target: rest } : undefined;
    case "KICK":
      return rest ? { type: "kick", target: rest } : undefined;
    case "LEAVE":
      return { type: "leave" };
    case "LEADER":
      return rest ? { type: "leader", target: rest } : undefined;
    case "ACCEPT":
      return { type: "accept" };
    case "DECLINE":
      return { type: "decline" };
    case "NEARBY":
      return { type: "nearby" };
    case "NEARBY_JSON":
      return { type: "nearby_json" };
    case "FRIENDS":
      return { type: "friends" };
    case "FRIENDS_JSON":
      return { type: "friends_json" };
    case "ADD_FRIEND":
      return rest ? { type: "add_friend", target: rest } : undefined;
    case "DEL_FRIEND":
      return rest ? { type: "del_friend", target: rest } : undefined;
    case "IGNORE":
      return { type: "unimplemented", feature: "Ignore list" };
    case "JOIN":
      return { type: "unimplemented", feature: "Channel join/leave" };
    case "GINVITE":
    case "GKICK":
    case "GLEAVE":
    case "GPROMOTE":
      return { type: "unimplemented", feature: "Guild management" };
    case "MAIL":
      return { type: "unimplemented", feature: "Mail" };
    case "ROLL": {
      const parts = rest.split(" ").filter(Boolean);
      if (parts.length >= 2)
        return {
          type: "roll",
          min: parseInt(parts[0]!, 10),
          max: parseInt(parts[1]!, 10),
        };
      if (parts.length === 1)
        return { type: "roll", min: 1, max: parseInt(parts[0]!, 10) };
      return { type: "roll", min: 1, max: 100 };
    }
    default:
      return line ? { type: "chat", message: line } : undefined;
  }
}

export function writeLines(socket: IpcSocket, lines: string[]): void {
  for (const line of lines) socket.write(line + "\n");
  socket.write("\n");
}

function drainText(events: RingBuffer<EventEntry>): string[] {
  return events.drain().flatMap((e) => (e.text !== undefined ? [e.text] : []));
}

function drainJson(events: RingBuffer<EventEntry>): string[] {
  return events.drain().map((e) => e.json);
}

function sliceText(events: RingBuffer<EventEntry>, from: number): string[] {
  return events
    .slice(from)
    .flatMap((e) => (e.text !== undefined ? [e.text] : []));
}

function sliceJson(events: RingBuffer<EventEntry>, from: number): string[] {
  return events.slice(from).map((e) => e.json);
}

export async function dispatchCommand(
  cmd: IpcCommand,
  handle: WorldHandle,
  events: RingBuffer<EventEntry>,
  socket: IpcSocket,
  cleanup: () => void,
): Promise<boolean> {
  switch (cmd.type) {
    case "chat": {
      handle.sendInCurrentMode(cmd.message);
      const mode = handle.getLastChatMode();
      const label =
        mode.type === "whisper"
          ? `WHISPER ${mode.target}`
          : mode.type === "channel"
            ? `CHANNEL ${mode.channel}`
            : mode.type.toUpperCase();
      writeLines(socket, [`OK ${label}`]);
      return false;
    }
    case "say":
      handle.sendSay(cmd.message);
      writeLines(socket, ["OK"]);
      return false;
    case "yell":
      handle.sendYell(cmd.message);
      writeLines(socket, ["OK"]);
      return false;
    case "guild":
      handle.sendGuild(cmd.message);
      writeLines(socket, ["OK"]);
      return false;
    case "party":
      handle.sendParty(cmd.message);
      writeLines(socket, ["OK"]);
      return false;
    case "emote":
      handle.sendEmote(cmd.message);
      writeLines(socket, ["OK"]);
      return false;
    case "dnd":
      handle.sendDnd(cmd.message);
      writeLines(socket, ["OK"]);
      return false;
    case "afk":
      handle.sendAfk(cmd.message);
      writeLines(socket, ["OK"]);
      return false;
    case "whisper":
      handle.sendWhisper(cmd.target, cmd.message);
      writeLines(socket, ["OK"]);
      return false;
    case "roll":
      handle.sendRoll(cmd.min, cmd.max);
      writeLines(socket, ["OK"]);
      return false;
    case "read":
      writeLines(socket, drainText(events));
      return false;
    case "read_json":
      writeLines(socket, drainJson(events));
      return false;
    case "read_wait": {
      const start = events.writePos;
      await new Promise<void>((resolve) => {
        setTimeout(() => {
          writeLines(socket, sliceText(events, start));
          resolve();
        }, cmd.ms);
      });
      return false;
    }
    case "read_wait_json": {
      const start = events.writePos;
      await new Promise<void>((resolve) => {
        setTimeout(() => {
          writeLines(socket, sliceJson(events, start));
          resolve();
        }, cmd.ms);
      });
      return false;
    }
    case "stop":
      writeLines(socket, ["OK"]);
      cleanup();
      return true;
    case "status":
      writeLines(socket, ["CONNECTED"]);
      return false;
    case "who": {
      const results = await handle.who(cmd.filter ? { name: cmd.filter } : {});
      writeLines(socket, formatWhoResults(results).split("\n"));
      return false;
    }
    case "who_json": {
      const results = await handle.who(cmd.filter ? { name: cmd.filter } : {});
      writeLines(socket, [formatWhoResultsJson(results)]);
      return false;
    }
    case "invite":
      handle.invite(cmd.target);
      writeLines(socket, ["OK"]);
      return false;
    case "kick":
      handle.uninvite(cmd.target);
      writeLines(socket, ["OK"]);
      return false;
    case "leave":
      handle.leaveGroup();
      writeLines(socket, ["OK"]);
      return false;
    case "leader":
      handle.setLeader(cmd.target);
      writeLines(socket, ["OK"]);
      return false;
    case "accept":
      handle.acceptInvite();
      writeLines(socket, ["OK"]);
      return false;
    case "decline":
      handle.declineInvite();
      writeLines(socket, ["OK"]);
      return false;
    case "nearby": {
      const entities = handle.getNearbyEntities();
      writeLines(socket, entities.map(formatNearbyLine));
      return false;
    }
    case "nearby_json": {
      const entities = handle.getNearbyEntities();
      writeLines(
        socket,
        entities.map((e) => JSON.stringify(formatNearbyObj(e))),
      );
      return false;
    }
    case "friends": {
      const friends = handle.getFriends();
      writeLines(socket, formatFriendList(friends).split("\n"));
      return false;
    }
    case "friends_json": {
      const friends = handle.getFriends();
      writeLines(socket, [formatFriendListJson(friends)]);
      return false;
    }
    case "add_friend":
      handle.addFriend(cmd.target);
      writeLines(socket, ["OK"]);
      return false;
    case "del_friend":
      handle.removeFriend(cmd.target);
      writeLines(socket, ["OK"]);
      return false;
    case "unimplemented":
      writeLines(socket, [`UNIMPLEMENTED ${cmd.feature}`]);
      return false;
  }
}

function objectTypeName(type: ObjectType): string {
  switch (type) {
    case ObjectType.UNIT:
      return "NPC";
    case ObjectType.PLAYER:
      return "Player";
    default:
      return `type ${type}`;
  }
}

function formatNearbyLine(entity: Entity): string {
  if (
    entity.objectType === ObjectType.UNIT ||
    entity.objectType === ObjectType.PLAYER
  ) {
    const unit = entity as UnitEntity;
    const name = entity.name ?? "Unknown";
    const kind = objectTypeName(entity.objectType);
    const level = unit.level > 0 ? `, level ${unit.level}` : "";
    const hp = `HP ${unit.health}/${unit.maxHealth}`;
    const pos = entity.position
      ? ` at ${entity.position.x.toFixed(2)}, ${entity.position.y.toFixed(2)}, ${entity.position.z.toFixed(2)}`
      : "";
    return `${name} (${kind}${level}) ${hp}${pos}`;
  }
  if (entity.objectType === ObjectType.GAMEOBJECT) {
    const name = entity.name ?? "Unknown";
    const pos = entity.position
      ? ` at ${entity.position.x.toFixed(2)}, ${entity.position.y.toFixed(2)}, ${entity.position.z.toFixed(2)}`
      : "";
    return `${name} (GameObject)${pos}`;
  }
  return `Entity 0x${entity.guid.toString(16)} (${objectTypeName(entity.objectType)})`;
}

function objectTypeString(type: ObjectType): string {
  switch (type) {
    case ObjectType.UNIT:
      return "unit";
    case ObjectType.PLAYER:
      return "player";
    case ObjectType.GAMEOBJECT:
      return "gameobject";
    default:
      return "object";
  }
}

function formatNearbyObj(entity: Entity): Record<string, unknown> {
  const obj: Record<string, unknown> = {
    guid: `0x${entity.guid.toString(16)}`,
    type: objectTypeString(entity.objectType),
    name: entity.name,
  };
  if (
    entity.objectType === ObjectType.UNIT ||
    entity.objectType === ObjectType.PLAYER
  ) {
    const unit = entity as UnitEntity;
    obj["level"] = unit.level;
    obj["health"] = unit.health;
    obj["maxHealth"] = unit.maxHealth;
  }
  if (entity.objectType === ObjectType.GAMEOBJECT) {
    obj["gameObjectType"] = (entity as GameObjectEntity).gameObjectType;
  }
  if (entity.position) {
    obj["x"] = entity.position.x;
    obj["y"] = entity.position.y;
    obj["z"] = entity.position.z;
  }
  return obj;
}

function formatGroupEventObj(event: GroupEvent): Record<string, unknown> {
  switch (event.type) {
    case "invite_received":
      return { type: "GROUP_INVITE", from: event.from };
    case "command_result":
      return {
        type: "GROUP_COMMAND_RESULT",
        operation: event.operation,
        target: event.target,
        result: event.result,
      };
    case "leader_changed":
      return { type: "GROUP_LEADER_CHANGED", name: event.name };
    case "group_destroyed":
      return { type: "GROUP_DESTROYED" };
    case "kicked":
      return { type: "GROUP_KICKED" };
    case "invite_declined":
      return { type: "GROUP_INVITE_DECLINED", name: event.name };
    case "group_list":
      return {
        type: "GROUP_LIST",
        members: event.members.map((m) => ({
          name: m.name,
          online: m.online,
        })),
        leader: event.leader,
      };
    case "member_stats":
      return {
        type: "PARTY_MEMBER_STATS",
        guidLow: event.guidLow,
        online: event.online,
        hp: event.hp,
        maxHp: event.maxHp,
        level: event.level,
      };
  }
}

export function onGroupEvent(
  event: GroupEvent,
  events: RingBuffer<EventEntry>,
  log: SessionLog,
): void {
  const text = formatGroupEvent(event);
  const obj = formatGroupEventObj(event);
  events.push({ text, json: JSON.stringify(obj) });
  log.append(obj as LogEntry).catch(() => {});
}

export function onChatMessage(
  msg: ChatMessage,
  events: RingBuffer<EventEntry>,
  log: SessionLog,
): void {
  const obj = formatMessageObj(msg);
  events.push({ text: formatMessage(msg), json: JSON.stringify(obj) });
  log.append(obj).catch(() => {});
}

export function onEntityEvent(
  event: EntityEvent,
  events: RingBuffer<EventEntry>,
  log: SessionLog,
): void {
  const text = formatEntityEvent(event);
  const obj = formatEntityEventObj(event);
  if (obj) {
    events.push({ text, json: JSON.stringify(obj) });
    log.append(obj as LogEntry).catch(() => {});
  }
}

export function onFriendEvent(
  event: FriendEvent,
  events: RingBuffer<EventEntry>,
  log: SessionLog,
): void {
  const text = formatFriendEvent(event);
  const obj = formatFriendEventObj(event);
  if (obj) {
    events.push({ text, json: JSON.stringify(obj) });
    log.append(obj as LogEntry).catch(() => {});
  }
}

