      if (interactive) {
        rl.setPrompt(formatPrompt(handle.getLastChatMode()));
        rl.prompt();
      }
    });

    rl.on("SIGINT", () => {
      handle.close();
      rl.close();
    });

    rl.on("close", () => {
      handle.close();
      resolve();
    });

    handle.closed.then(() => rl.close());
  });
}

